import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.xml.ws.BindingType;
import javax.xml.ws.soap.SOAPBinding;
import javax.xml.ws.handler.MessageContext;
import javax.xml.soap.SOAPMessage;
import javax.xml.soap.SOAPHeader;
import javax.xml.soap.SOAPElement;
import javax.xml.namespace.QName;
import java.util.Date;
import java.util.Map;
import java.util.GregorianCalendar;
import java.text.SimpleDateFormat;
import java.util.TimeZone;
import javax.xml.ws.WebServiceException;

@WebService
@BindingType(SOAPBinding.SOAP12HTTP_BINDING)
public class PaymentGatewayService {
    
    private static final long TIMESTAMP_TOLERANCE = 300000; // 5 minutes
    
    @WebMethod
    public PaymentResponse processPayment(PaymentRequest request) {
        try {
            validateTimestamp();
            validateRequest(request);
            
            PaymentResponse response = new PaymentResponse();
            response.setTransactionId(generateTransactionId());
            response.setStatus("SUCCESS");
            response.setTimestamp(new Date());
            
            return response;
        } catch (Exception e) {
            PaymentResponse response = new PaymentResponse();
            response.setStatus("FAILED");
            response.setErrorMessage(e.getMessage());
            return response;
        }
    }
    
    private void validateTimestamp() throws Exception {
        MessageContext context = MessageContext.getCurrentContext();
        SOAPMessage message = (SOAPMessage) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        SOAPHeader header = message.getSOAPHeader();
        
        if (header == null) {
            throw new WebServiceException("Missing SOAP header");
        }
        
        SOAPElement timestampElement = (SOAPElement) header.getElementsByTagNameNS(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", 
            "Timestamp"
        ).item(0);
        
        if (timestampElement == null) {
            throw new WebServiceException("Missing timestamp in SOAP header");
        }
        
        String created = getTimestampValue(timestampElement, "Created");
        String expires = getTimestampValue(timestampElement, "Expires");
        
        if (created == null) {
            throw new WebServiceException("Missing created timestamp");
        }
        
        Date createdDate = parseTimestamp(created);
        Date expiresDate = parseTimestamp(expires);
        
        if (isExpired(createdDate, expiresDate)) {
            throw new WebServiceException("Timestamp has expired");
        }
        
        if (isReplayAttack(createdDate)) {
            throw new WebServiceException("Replay attack detected");
        }
    }
    
    private String getTimestampValue(SOAPElement timestampElement, String elementName) {
        SOAPElement element = (SOAPElement) timestampElement.getElementsByTagName(elementName).item(0);
        return element != null ? element.getTextContent() : null;
    }
    
    private Date parseTimestamp(String timestamp) throws Exception {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
        return sdf.parse(timestamp);
    }
    
    private boolean isExpired(Date created, Date expires) {
        long currentTime = System.currentTimeMillis();
        return currentTime > expires.getTime();
    }
    
    private boolean isReplayAttack(Date created) throws Exception {
        long currentTime = System.currentTimeMillis();
        long createdTime = created.getTime();
        
        if (Math.abs(currentTime - createdTime) > TIMESTAMP_TOLERANCE) {
            return true;
        }
        
        return false;
    }
    
    private void validateRequest(PaymentRequest request) throws Exception {
        if (request.getAmount() <= 0) {
            throw new WebServiceException("Invalid amount");
        }
        
        if (request.getCreditCardNumber() == null || request.getCreditCardNumber().length() < 13) {
            throw new WebServiceException("Invalid credit card number");
        }
        
        if (request.getExpirationDate() == null) {
            throw new WebServiceException("Invalid expiration date");
        }
    }
    
    private String generateTransactionId() {
        return "TXN" + System.currentTimeMillis();
    }
}

